def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 8):
            base_term = ((-1) ** j) * (ratio ** j) / (j + 0.5)
            if j % 3 == 0:
                base_term *= np.exp(-ratio * j)
            elif j % 2 == 0:
                base_term *= 1.7
            else:
                base_term *= 0.85
            score += base_term
        if capacity < item * 1.1:
            score *= 4
            for k in range(1, 5):
                score += ((-1) ** (k+1)) * (ratio ** (k+6)) / (k+6) * np.tanh(ratio * k)
            if score < 0:
                score = abs(score) * 0.5
        elif capacity < item * 1.8:
            score *= 2
            for k in range(4):
                score += np.sin(ratio * (k + 2)) / (k + 2) * np.cos(ratio * (k + 1))
            if score > 1:
                score /= 2
        elif capacity > item * 3.5:
            score /= 4
            for k in range(3, 7):
                score -= np.log1p(ratio * k) / (k + 1) * np.sin(ratio / (k + 1))
            if score > 0:
                score = -score * 1.2
        else:
            for k in range(1, 5):
                score += (ratio ** k) * np.cos(k * ratio) / (k + 3) * np.exp(-ratio / (k + 1))
            if np.isclose(score, 0, atol=1e-6):
                score = 1e-3
        if np.isnan(score) or np.isinf(score) or score == 0:
            priorities[i] = np.inf
        else:
            priorities[i] = -score
    return priorities
